import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

describe('geo()', () => {
  it('extracts geolocation from Vercel headers', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'New York',
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'NY',
      'x-vercel-ip-latitude': '40.7128',
      'x-vercel-ip-longitude': '-74.0060',
      'x-vercel-ip-timezone': 'America/New_York',
    })
    const result = geo({ headers })
    expect(result.city).toBe('New York')
    expect(result.countryCode).toBe('US')
    expect(result.country).toBe('United States')
    expect(result.region).toBe('NY')
    expect(result.latitude).toBe('40.7128')
    expect(result.longitude).toBe('-74.0060')
    expect(result.timezone).toBe('America/New_York')
  })

  it('returns undefined fields when headers are missing', () => {
    const headers = new Headers()
    const result = geo({ headers })
    expect(result.city).toBeUndefined()
    expect(result.countryCode).toBeUndefined()
    expect(result.country).toBeUndefined()
    expect(result.region).toBeUndefined()
    expect(result.latitude).toBeUndefined()
    expect(result.longitude).toBeUndefined()
    expect(result.timezone).toBeUndefined()
  })
})

describe('geoFromHeaders()', () => {
  it('extracts geolocation from raw Headers', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'Tokyo',
      'x-vercel-ip-country': 'JP',
      'x-vercel-ip-country-region': 'TK',
      'x-vercel-ip-latitude': '35.6762',
      'x-vercel-ip-longitude': '139.6503',
      'x-vercel-ip-timezone': 'Asia/Tokyo',
    })
    const result = geoFromHeaders(headers)
    expect(result.city).toBe('Tokyo')
    expect(result.countryCode).toBe('JP')
    expect(result.country).toBe('Japan')
    expect(result.region).toBe('TK')
    expect(result.latitude).toBe('35.6762')
    expect(result.longitude).toBe('139.6503')
    expect(result.timezone).toBe('Asia/Tokyo')
  })

  it('falls back to cf-ipcountry when x-vercel-ip-country is absent', () => {
    const headers = new Headers({
      'cf-ipcountry': 'DE',
    })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('DE')
    expect(result.country).toBe('Germany')
  })

  it('prefers x-vercel-ip-country over cf-ipcountry', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'FR',
      'cf-ipcountry': 'DE',
    })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('FR')
    expect(result.country).toBe('France')
  })

  it('returns undefined country for unknown countryCode', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'ZZ',
    })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('ZZ')
    expect(result.country).toBeUndefined()
  })
})

describe('isInRegion()', () => {
  it('returns true when countryCode matches a region in the list', () => {
    const geoData = { countryCode: 'US' }
    expect(isInRegion(geoData, ['US', 'CA', 'GB'])).toBe(true)
  })

  it('returns false when countryCode is not in the list', () => {
    const geoData = { countryCode: 'JP' }
    expect(isInRegion(geoData, ['US', 'CA', 'GB'])).toBe(false)
  })

  it('is case-insensitive', () => {
    const geoData = { countryCode: 'us' }
    expect(isInRegion(geoData, ['US'])).toBe(true)
  })

  it('returns false when countryCode is undefined', () => {
    const geoData = {}
    expect(isInRegion(geoData, ['US'])).toBe(false)
  })
})

describe('geoDistance()', () => {
  it('calculates distance from New York to London within 50 km of ~5570 km', () => {
    // New York: 40.7128° N, 74.0060° W
    // London:   51.5074° N,  0.1278° W
    const dist = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    expect(dist).toBeGreaterThan(5520)
    expect(dist).toBeLessThan(5620)
  })

  it('returns 0 for the same point', () => {
    const dist = geoDistance('48.8566', '2.3522', '48.8566', '2.3522')
    expect(dist).toBeCloseTo(0, 5)
  })

  it('calculates AU to IN distance in a reasonable range', () => {
    // Sydney: -33.8688, 151.2093
    // Mumbai:  19.0760,  72.8777
    const dist = geoDistance('-33.8688', '151.2093', '19.0760', '72.8777')
    expect(dist).toBeGreaterThan(9000)
    expect(dist).toBeLessThan(10500)
  })
})

describe('country name lookup', () => {
  const cases: [string, string][] = [
    ['AU', 'Australia'],
    ['BR', 'Brazil'],
    ['CA', 'Canada'],
    ['CN', 'China'],
    ['DE', 'Germany'],
    ['FR', 'France'],
    ['GB', 'United Kingdom'],
    ['IN', 'India'],
    ['JP', 'Japan'],
    ['US', 'United States'],
  ]

  test.each(cases)('countryCode %s maps to %s', (code, name) => {
    const headers = new Headers({ 'x-vercel-ip-country': code })
    const result = geoFromHeaders(headers)
    expect(result.country).toBe(name)
  })
})

